import{_ as e,b as o,o as c,i as a,j as r,g as l,aB as n}from"./chunks/framework._ZAOES46.js";const D=JSON.parse('{"title":"FaDate 日期","description":"","frontmatter":{},"headers":[],"relativePath":"components/pro/FaDate.md","filePath":"components/pro/FaDate.md"}'),i={name:"components/pro/FaDate.md"};function s(u,d,h,p,b,g){const t=o("Badge");return c(),a("div",null,[d[0]||(d[0]=r("div",{style:{display:"none"},hidden:"true","aria-hidden":"true","data-nosnippet":""},"Are you an LLM? You can read better optimized documentation at /components/pro/FaDate.md for this page in Markdown format",-1)),l(t,{type:"pro",text:"专业版"}),d[1]||(d[1]=n('<h1 id="fadate-日期" tabindex="-1">FaDate 日期 <a class="header-anchor" href="#fadate-日期" aria-label="Permalink to “FaDate 日期”">​</a></h1><p>基于 <code>FaCalendarDate</code>、<code>FaCalendarMonth</code>、<code>FaCalendarYear</code> 组合的日期组件。默认渲染面板，设置 <code>picker</code> 后渲染为按钮触发的弹层选择器。月视图和年视图只用于切换当前展示锚点，不会提交日期值。</p><h2 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to “使用场景”">​</a></h2><ul><li>需要通过年、月、日三层视图选择日期</li><li>日期跨度较大，例如生日、历史日期、预约日期</li><li>需要复用框架内建日历组件和值类型语义</li></ul><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to “Props”">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>类型</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>modelValue</code></td><td><code>DateValue | DateValue[]</code></td><td>-</td><td>受控选中日期，支持 <code>v-model</code></td></tr><tr><td><code>defaultValue</code></td><td><code>DateValue | DateValue[]</code></td><td>-</td><td>非受控初始选中日期</td></tr><tr><td><code>placeholder</code></td><td><code>DateValue</code></td><td>-</td><td>受控展示锚点，支持 <code>v-model:placeholder</code></td></tr><tr><td><code>defaultPlaceholder</code></td><td><code>DateValue</code></td><td>今天</td><td>非受控初始展示锚点</td></tr><tr><td><code>view</code></td><td><code>&#39;date&#39; | &#39;month&#39; | &#39;year&#39;</code></td><td>-</td><td>受控视图，支持 <code>v-model:view</code></td></tr><tr><td><code>defaultView</code></td><td><code>&#39;date&#39; | &#39;month&#39; | &#39;year&#39;</code></td><td><code>&#39;date&#39;</code></td><td>非受控初始视图</td></tr><tr><td><code>minValue</code></td><td><code>DateValue</code></td><td>-</td><td>最小可选日期</td></tr><tr><td><code>maxValue</code></td><td><code>DateValue</code></td><td>-</td><td>最大可选日期</td></tr><tr><td><code>multiple</code></td><td><code>boolean</code></td><td>按值类型推断</td><td>是否启用多选</td></tr><tr><td><code>disabled</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否禁用</td></tr><tr><td><code>readonly</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否只读</td></tr><tr><td><code>locale</code></td><td><code>string</code></td><td><code>&#39;zh-CN&#39;</code></td><td>日期格式化语言</td></tr><tr><td><code>dir</code></td><td><code>&#39;ltr&#39; | &#39;rtl&#39;</code></td><td>跟随文档方向</td><td>阅读方向</td></tr><tr><td><code>weekStartsOn</code></td><td><code>0 | 1 | 2 | 3 | 4 | 5 | 6</code></td><td><code>1</code></td><td>一周起始日</td></tr><tr><td><code>weekdayFormat</code></td><td><code>&#39;narrow&#39; | &#39;short&#39; | &#39;long&#39;</code></td><td><code>&#39;short&#39;</code></td><td>星期标题格式</td></tr><tr><td><code>fixedWeeks</code></td><td><code>boolean</code></td><td><code>true</code></td><td>日期视图是否固定 6 行</td></tr><tr><td><code>numberOfMonths</code></td><td><code>number</code></td><td><code>1</code></td><td>日期视图同时展示的月份数量</td></tr><tr><td><code>pagedNavigation</code></td><td><code>boolean</code></td><td><code>false</code></td><td>多月展示时是否按页翻动</td></tr><tr><td><code>preventDeselect</code></td><td><code>boolean</code></td><td>单选 <code>true</code>，多选 <code>false</code></td><td>是否禁止点击已选日期取消选择</td></tr><tr><td><code>initialFocus</code></td><td><code>boolean</code></td><td><code>false</code></td><td>挂载后是否自动聚焦</td></tr><tr><td><code>disableDaysOutsideCurrentView</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否禁用当前视图外的日期</td></tr><tr><td><code>isDateDisabled</code></td><td><code>(date: DateValue) =&gt; boolean</code></td><td>-</td><td>判断日期是否禁用</td></tr><tr><td><code>isDateUnavailable</code></td><td><code>(date: DateValue) =&gt; boolean</code></td><td>-</td><td>判断日期是否不可用</td></tr><tr><td><code>isMonthDisabled</code></td><td><code>(month: DateValue) =&gt; boolean</code></td><td>-</td><td>判断月份是否禁用</td></tr><tr><td><code>isMonthUnavailable</code></td><td><code>(month: DateValue) =&gt; boolean</code></td><td>-</td><td>判断月份是否不可用</td></tr><tr><td><code>isYearDisabled</code></td><td><code>(year: DateValue) =&gt; boolean</code></td><td>-</td><td>判断年份是否禁用</td></tr><tr><td><code>isYearUnavailable</code></td><td><code>(year: DateValue) =&gt; boolean</code></td><td>-</td><td>判断年份是否不可用</td></tr><tr><td><code>calendarLabel</code></td><td><code>string</code></td><td><code>&#39;日期选择&#39;</code></td><td>日期视图无障碍标签</td></tr><tr><td><code>monthCalendarLabel</code></td><td><code>string</code></td><td><code>&#39;月份选择&#39;</code></td><td>月份视图无障碍标签</td></tr><tr><td><code>yearCalendarLabel</code></td><td><code>string</code></td><td><code>&#39;年份选择&#39;</code></td><td>年份视图无障碍标签</td></tr><tr><td><code>monthNextPage</code></td><td><code>(placeholder: DateValue) =&gt; DateValue</code></td><td>-</td><td>月份视图下一页函数</td></tr><tr><td><code>monthPrevPage</code></td><td><code>(placeholder: DateValue) =&gt; DateValue</code></td><td>-</td><td>月份视图上一页函数</td></tr><tr><td><code>yearNextPage</code></td><td><code>(placeholder: DateValue) =&gt; DateValue</code></td><td>-</td><td>年份视图下一页函数</td></tr><tr><td><code>yearPrevPage</code></td><td><code>(placeholder: DateValue) =&gt; DateValue</code></td><td>-</td><td>年份视图上一页函数</td></tr><tr><td><code>yearsPerPage</code></td><td><code>number</code></td><td><code>12</code></td><td>年份视图每页展示年份数</td></tr><tr><td><code>picker</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否启用内置选择器形态</td></tr><tr><td><code>open</code></td><td><code>boolean</code></td><td>-</td><td>受控弹层打开状态，支持 <code>v-model:open</code></td></tr><tr><td><code>defaultOpen</code></td><td><code>boolean</code></td><td><code>false</code></td><td>非受控初始弹层打开状态</td></tr><tr><td><code>pickerPlaceholder</code></td><td><code>string</code></td><td><code>&#39;选择日期&#39;</code></td><td>选择器按钮空值文案</td></tr><tr><td><code>formatValue</code></td><td><code>(value: DateValue | DateValue[] | undefined) =&gt; string</code></td><td>-</td><td>自定义选择器按钮展示文案</td></tr><tr><td><code>formatMonthLabel</code></td><td><code>(date: DateValue) =&gt; string</code></td><td>-</td><td>自定义月份标题文案</td></tr><tr><td><code>formatYearLabel</code></td><td><code>(date: DateValue) =&gt; string</code></td><td>-</td><td>自定义年份标题文案</td></tr><tr><td><code>formatYearRangeLabel</code></td><td><code>(start: DateValue, end: DateValue) =&gt; string</code></td><td>-</td><td>自定义年份范围标题文案</td></tr><tr><td><code>closeOnSelect</code></td><td><code>boolean</code></td><td>单选 <code>true</code>，多选 <code>false</code></td><td>选择日期后是否自动关闭弹层</td></tr><tr><td><code>triggerClass</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>选择器触发按钮 class</td></tr><tr><td><code>triggerVariant</code></td><td><code>ButtonVariants[&#39;variant&#39;]</code></td><td><code>&#39;outline&#39;</code></td><td>选择器触发按钮风格</td></tr><tr><td><code>triggerSize</code></td><td><code>ButtonVariants[&#39;size&#39;]</code></td><td><code>&#39;default&#39;</code></td><td>选择器触发按钮尺寸</td></tr><tr><td><code>triggerIcon</code></td><td><code>string | false</code></td><td><code>&#39;i-lucide:calendar&#39;</code></td><td>选择器触发按钮图标</td></tr><tr><td><code>contentClass</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>选择器弹层内容 class</td></tr><tr><td><code>popoverAlign</code></td><td><code>PopoverContentProps[&#39;align&#39;]</code></td><td>-</td><td>弹层对齐方式</td></tr><tr><td><code>popoverAlignOffset</code></td><td><code>PopoverContentProps[&#39;alignOffset&#39;]</code></td><td>-</td><td>弹层对齐偏移</td></tr><tr><td><code>popoverSide</code></td><td><code>PopoverContentProps[&#39;side&#39;]</code></td><td>-</td><td>弹层弹出方向</td></tr><tr><td><code>popoverSideOffset</code></td><td><code>PopoverContentProps[&#39;sideOffset&#39;]</code></td><td>-</td><td>弹层方向偏移</td></tr><tr><td><code>popoverCollisionPadding</code></td><td><code>PopoverContentProps[&#39;collisionPadding&#39;]</code></td><td>-</td><td>弹层碰撞边距</td></tr><tr><td><code>class</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>当前面板 class</td></tr></tbody></table><h2 id="slots" tabindex="-1">Slots <a class="header-anchor" href="#slots" aria-label="Permalink to “Slots”">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>说明</th><th>作用域参数</th></tr></thead><tbody><tr><td><code>trigger</code></td><td>自定义选择器触发器，仅 <code>picker</code> 模式生效</td><td><code>value, label, open, disabled, readonly</code></td></tr></tbody></table><h2 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to “Events”">​</a></h2><table tabindex="0"><thead><tr><th>事件名</th><th>说明</th><th>回调参数</th></tr></thead><tbody><tr><td><code>update:modelValue</code></td><td>选中日期更新，用于 <code>v-model</code></td><td><code>value: DateValue | DateValue[] | undefined</code></td></tr><tr><td><code>change</code></td><td>用户交互导致日期值变化时触发</td><td><code>value: DateValue | DateValue[] | undefined</code></td></tr><tr><td><code>update:placeholder</code></td><td>展示锚点变化，用于 <code>v-model:placeholder</code></td><td><code>value: DateValue</code></td></tr><tr><td><code>update:open</code></td><td>选择器弹层打开状态变化，用于 <code>v-model:open</code></td><td><code>value: boolean</code></td></tr><tr><td><code>update:view</code></td><td>当前视图变化，用于 <code>v-model:view</code></td><td><code>view: &#39;date&#39; | &#39;month&#39; | &#39;year&#39;</code></td></tr></tbody></table><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><ol><li><code>modelValue</code> 始终表示日期值；选择月份和年份只会更新 <code>placeholder</code> 与 <code>view</code>。</li><li><code>picker</code> 模式每次打开时，非受控 <code>view</code> 会重置为 <code>defaultView</code>。</li><li><code>closeOnSelect</code> 只在日期视图选择日期后生效；选择月份、年份不会关闭弹层。</li><li>月份和年份禁用状态不会从 <code>isDateDisabled</code> 自动推导，如需限制请传入对应回调。</li><li>范围选择请使用已有范围组件；<code>FaDate</code> 不提供 <code>range</code> prop。</li></ol>',12))])}const f=e(i,[["render",s]]);export{D as __pageData,f as default};
